'use client'

import { cn } from '@/lib/utils'
import { Medal, Award, Crown, Sparkles } from 'lucide-react'

interface UserLevelBadgeProps {
    level: number
    tier: 'bronze' | 'silver' | 'gold' | 'platinum'
    name?: string
    size?: 'sm' | 'md' | 'lg'
    showTooltip?: boolean
}

const tierConfig = {
    bronze: {
        icon: Medal,
        bgColor: 'bg-amber-100 dark:bg-amber-900/30',
        textColor: 'text-amber-700 dark:text-amber-400',
        borderColor: 'border-amber-300 dark:border-amber-700',
        gradient: 'from-amber-500 to-amber-700',
    },
    silver: {
        icon: Award,
        bgColor: 'bg-gray-100 dark:bg-gray-800',
        textColor: 'text-gray-600 dark:text-gray-300',
        borderColor: 'border-gray-300 dark:border-gray-600',
        gradient: 'from-gray-400 to-gray-600',
    },
    gold: {
        icon: Crown,
        bgColor: 'bg-yellow-100 dark:bg-yellow-900/30',
        textColor: 'text-yellow-700 dark:text-yellow-400',
        borderColor: 'border-yellow-400 dark:border-yellow-600',
        gradient: 'from-yellow-400 to-yellow-600',
    },
    platinum: {
        icon: Sparkles,
        bgColor: 'bg-purple-100 dark:bg-purple-900/30',
        textColor: 'text-purple-700 dark:text-purple-400',
        borderColor: 'border-purple-400 dark:border-purple-600',
        gradient: 'from-purple-500 to-purple-700',
    },
}

const sizeConfig = {
    sm: {
        container: 'h-6 px-2 gap-1',
        icon: 'w-3 h-3',
        text: 'text-xs',
    },
    md: {
        container: 'h-8 px-3 gap-1.5',
        icon: 'w-4 h-4',
        text: 'text-sm',
    },
    lg: {
        container: 'h-10 px-4 gap-2',
        icon: 'w-5 h-5',
        text: 'text-base',
    },
}

export function UserLevelBadge({
    level,
    tier,
    name,
    size = 'md',
    showTooltip = true
}: UserLevelBadgeProps) {
    const config = tierConfig[tier]
    const sizeStyles = sizeConfig[size]
    const Icon = config.icon

    return (
        <div className="relative group inline-flex">
            <div
                className={cn(
                    "inline-flex items-center rounded-full border font-medium transition-all",
                    config.bgColor,
                    config.textColor,
                    config.borderColor,
                    sizeStyles.container
                )}
            >
                <Icon className={cn(sizeStyles.icon)} />
                <span className={cn("font-bold", sizeStyles.text)}>
                    {level}
                </span>
            </div>

            {/* Tooltip */}
            {showTooltip && name && (
                <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 px-3 py-1.5 bg-gray-900 dark:bg-gray-100 text-white dark:text-gray-900 text-xs rounded-lg opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap pointer-events-none z-10">
                    <span className="font-medium">Level {level}</span>
                    <span className="mx-1">·</span>
                    <span>{name}</span>
                    <div className="absolute bottom-0 left-1/2 -translate-x-1/2 translate-y-full">
                        <div className="w-2 h-2 bg-gray-900 dark:bg-gray-100 rotate-45 -translate-y-1" />
                    </div>
                </div>
            )}
        </div>
    )
}

// Utility to get tier from level
export function getTierFromLevel(level: number): 'bronze' | 'silver' | 'gold' | 'platinum' {
    if (level <= 10) return 'bronze'
    if (level <= 25) return 'silver'
    if (level <= 40) return 'gold'
    return 'platinum'
}
